import React, { useState, useContext } from 'react';
import { View, TextInput, Button, Text, StyleSheet } from 'react-native';
import { AppContext } from '../context/AppContext';
import theme from '../theme';

export default function JoinGroupScreen({ navigation }) {
  const [groupId, setGroupId] = useState('');
  const [message, setMessage] = useState('');
  const { joinGroupById } = useContext(AppContext);

  const handleJoin = () => {
    const res = joinGroupById(groupId.trim());
    if (res.success) {
      navigation.replace('Chat', { groupId: groupId.trim() });
    } else {
      setMessage(res.message || 'Unable to join');
    }
  };

  return (
    <View style={styles.container}>
      <TextInput placeholder="Enter Group ID (e.g. g-123)" value={groupId} onChangeText={setGroupId} style={styles.input} />
      <Button title="Join Group" onPress={handleJoin} />
      {message ? <Text style={{ color: theme.warning, marginTop: 8 }}>{message}</Text> : null}
    </View>
  );
}

const styles = StyleSheet.create({ container: { flex: 1, padding: 16 }, input: { borderWidth: 1, borderColor: theme.secondary, padding: 10, borderRadius: 12, marginBottom: 12 } });
